import { z } from 'zod';

export const adoptionStep1Schema = z.object({
  applicant_name: z.string().min(2, 'Name is required'),
  applicant_email: z.string().email('Valid email required'),
  applicant_phone: z.string().min(10, 'Phone number required'),
});

export const adoptionStep2Schema = z.object({
  housing_type: z.enum(['house', 'apartment', 'condo', 'other']),
  has_yard: z.boolean(),
  other_pets: z.string().optional(),
});

export const adoptionStep3Schema = z.object({
  experience: z.string().min(10, 'Please describe your experience'),
  why_adopt: z.string().min(10, 'Please tell us why you want to adopt'),
});

export const adoptionSchema = adoptionStep1Schema
  .merge(adoptionStep2Schema)
  .merge(adoptionStep3Schema);

export type AdoptionFormData = z.infer<typeof adoptionSchema>;

