'use client';

import { useState, ReactNode } from 'react';
import { ZodSchema } from 'zod';
import { Button } from '@/components/ui/Button';
import clsx from 'clsx';

export interface FormStep {
  title: string;
  schema: ZodSchema;
  render: (data: Record<string, any>, onChange: (key: string, value: any) => void, errors: Record<string, string>) => ReactNode;
}

interface MultiStepFormProps {
  steps: FormStep[];
  onSubmit: (data: Record<string, any>) => Promise<void>;
  submitLabel?: string;
}

export function MultiStepForm({ steps, onSubmit, submitLabel = 'Submit' }: MultiStepFormProps) {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const step = steps[currentStep];

  const handleChange = (key: string, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
    setErrors(prev => { const next = { ...prev }; delete next[key]; return next; });
  };

  const validateCurrentStep = () => {
    const result = step.schema.safeParse(formData);
    if (!result.success) {
      const fieldErrors: Record<string, string> = {};
      result.error.errors.forEach(e => {
        if (e.path[0]) fieldErrors[String(e.path[0])] = e.message;
      });
      setErrors(fieldErrors);
      return false;
    }
    setErrors({});
    return true;
  };

  const handleNext = () => {
    if (validateCurrentStep() && currentStep < steps.length - 1) {
      setCurrentStep(prev => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep(prev => prev - 1);
  };

  const handleSubmit = async () => {
    if (!validateCurrentStep()) return;
    setIsSubmitting(true);
    try {
      await onSubmit(formData);
    } finally {
      setIsSubmitting(false);
    }
  };

  const isLastStep = currentStep === steps.length - 1;

  return (
    <div className="w-full max-w-lg mx-auto">
      {/* Progress indicator */}
      <div className="flex items-center justify-center gap-2 mb-8">
        {steps.map((s, i) => (
          <div key={i} className="flex items-center gap-2">
            <div className={clsx(
              'h-8 w-8 rounded-full flex items-center justify-center text-sm font-medium',
              i <= currentStep ? 'bg-emerald-600 text-white' : 'bg-slate-200 text-slate-500'
            )}>
              {i + 1}
            </div>
            {i < steps.length - 1 && (
              <div className={clsx('h-0.5 w-8', i < currentStep ? 'bg-emerald-600' : 'bg-slate-200')} />
            )}
          </div>
        ))}
      </div>

      <h2 className="text-xl font-semibold mb-6">{step.title}</h2>

      {step.render(formData, handleChange, errors)}

      <div className="flex justify-between mt-8">
        <Button variant="outline" onClick={handleBack} disabled={currentStep === 0}>
          Back
        </Button>
        {isLastStep ? (
          <Button onClick={handleSubmit} disabled={isSubmitting}>
            {isSubmitting ? 'Submitting...' : submitLabel}
          </Button>
        ) : (
          <Button onClick={handleNext}>Next</Button>
        )}
      </div>
    </div>
  );
}

'use server';

import { adoptionSchema } from '@/lib/schemas/adoption';
import { db } from '@/lib/db';
import { adoptionApplications } from '@/drizzle/schema';
import { resend } from '@/lib/resend';

export async function submitAdoptionApplication(animalId: string, rawData: unknown) {
  const parsed = adoptionSchema.safeParse(rawData);
  if (!parsed.success) {
    return { error: 'Validation failed', issues: parsed.error.flatten().fieldErrors };
  }

  const data = parsed.data;

  const [application] = await db.insert(adoptionApplications).values({
    animal_id: animalId,
    applicant_name: data.applicant_name,
    applicant_email: data.applicant_email,
    applicant_phone: data.applicant_phone,
    housing_type: data.housing_type,
    has_yard: data.has_yard,
    other_pets: data.other_pets || null,
    experience: data.experience,
    why_adopt: data.why_adopt,
    status: 'submitted',
  }).returning();

  await resend.emails.send({
    from: 'PawFinder <noreply@pawfinder.org>',
    to: data.applicant_email,
    subject: 'Adoption Application Received',
    html: `<p>Hi ${data.applicant_name},</p><p>We've received your adoption application (ID: ${application.id}). Our team will review it and get back to you within 5-7 business days.</p><p>Thank you for choosing to adopt!</p>`,
  });

  return { success: true, applicationId: application.id };
}

'use server';

import { donationSchema } from '@/lib/schemas/donation';
import { stripe } from '@/lib/stripe';

export async function createDonationIntent(rawData: unknown) {
  const parsed = donationSchema.safeParse(rawData);
  if (!parsed.success) {
    return { error: 'Validation failed', issues: parsed.error.flatten().fieldErrors };
  }

  const data = parsed.data;

  if (data.is_recurring) {
    const customer = await stripe.customers.create({ email: data.donor_email });
    const price = await stripe.prices.create({
      unit_amount: data.amount_cents,
      currency: 'usd',
      recurring: { interval: 'month' },
      product_data: { name: 'Monthly Donation to PawFinder' },
    });
    const subscription = await stripe.subscriptions.create({
      customer: customer.id,
      items: [{ price: price.id }],
      payment_behavior: 'default_incomplete',
      expand: ['latest_invoice.payment_intent'],
    });
    const invoice = subscription.latest_invoice as any;
    return { clientSecret: invoice.payment_intent.client_secret, type: 'subscription' };
  }

  const paymentIntent = await stripe.paymentIntents.create({
    amount: data.amount_cents,
    currency: 'usd',
    metadata: {
      donor_name: data.donor_name || 'Anonymous',
      donor_email: data.donor_email,
      message: data.message || '',
    },
  });

  return { clientSecret: paymentIntent.client_secret, type: 'one_time' };
}

'use server';

import { contactSchema } from '@/lib/schemas/contact';
import { db } from '@/lib/db';
import { contactMessages } from '@/drizzle/schema';
import { resend } from '@/lib/resend';

const rateLimitMap = new Map<string, { count: number; resetAt: number }>();

export async function submitContactForm(rawData: unknown, clientIP?: string) {
  const parsed = contactSchema.safeParse(rawData);
  if (!parsed.success) {
    return { error: 'Validation failed', issues: parsed.error.flatten().fieldErrors };
  }

  if (clientIP) {
    const now = Date.now();
    const entry = rateLimitMap.get(clientIP);
    if (entry && entry.resetAt > now && entry.count >= 5) {
      return { error: 'Too many submissions. Please try again later.' };
    }
    if (!entry || entry.resetAt <= now) {
      rateLimitMap.set(clientIP, { count: 1, resetAt: now + 3600000 });
    } else {
      entry.count++;
    }
  }

  const data = parsed.data;

  await db.insert(contactMessages).values({
    name: data.name,
    email: data.email,
    subject: data.subject,
    message: data.message,
  });

  await resend.emails.send({
    from: 'PawFinder Contact <noreply@pawfinder.org>',
    to: 'info@pawfinder.org',
    subject: `[Contact] ${data.subject}`,
    html: `<p><strong>From:</strong> ${data.name} (${data.email})</p><p>${data.message}</p>`,
  });

  return { success: true };
}

import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

const s3 = new S3Client({
  region: process.env.AWS_REGION || 'us-east-1',
  credentials: {
    accessKeyId: process.env.AWS_ACCESS_KEY_ID!,
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY!,
  },
});

const BUCKET = process.env.S3_BUCKET || 'pawfinder-images-dev';
const MAX_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp'];

export async function generatePresignedUploadUrl(key: string, contentType: string) {
  if (!ALLOWED_TYPES.includes(contentType)) {
    throw new Error(`Unsupported content type: ${contentType}`);
  }

  const command = new PutObjectCommand({
    Bucket: BUCKET,
    Key: key,
    ContentType: contentType,
  });

  const url = await getSignedUrl(s3, command, { expiresIn: 300 });
  return url;
}

export function getImageUrl(key: string) {
  const cdnDomain = process.env.CLOUDFRONT_DOMAIN || 'images.pawfinder.org';
  return `https://${cdnDomain}/${key}`;
}

