    .from(animals)
    .where(eq(animals.status, 'available'))
    .orderBy(animals.created_at);

  return (
    <main className="max-w-6xl mx-auto px-4 py-12">
      <h1 className="text-3xl font-bold mb-2">Meet Our Animals</h1>
      <p className="text-slate-600 mb-8">Find your new best friend.</p>
